using LEGAL.Modello231.Api.Repositories;using LEGAL.Modello231.Api.Services;using LEGAL.Shared.Helpers;using Serilog;
EnvLoader.Load();Log.Logger=new LoggerConfiguration().MinimumLevel.Information().MinimumLevel.Override("Microsoft",Serilog.Events.LogEventLevel.Warning).WriteTo.Console().WriteTo.File("logs/modello231-.log",rollingInterval:RollingInterval.Day,retainedFileCountLimit:30).CreateLogger();
try{Log.Information("LEGAL Modello231 starting on port 5230...");var b=WebApplication.CreateBuilder(args);b.Host.UseSerilog();var cs=b.Configuration.GetValue<string>("Database:ConnectionString")??"Data Source=data/modello231.db";var repo=new Modello231Repository(cs);b.Services.AddSingleton(repo);b.Services.AddScoped<IModello231Service,Modello231Service>();b.Services.AddControllers();b.Services.AddEndpointsApiExplorer();b.Services.AddSwaggerGen(c=>{c.SwaggerDoc("v1",new(){Title="LEGAL Modello 231",Version="v1"});});b.Services.AddHealthChecks();b.Services.AddCors(o=>o.AddDefaultPolicy(p=>p.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader()));var app=b.Build();await repo.InitializeAsync();app.UseSerilogRequestLogging();app.UseCors();if(app.Environment.IsDevelopment()){app.UseSwagger();app.UseSwaggerUI();}app.MapControllers();app.MapHealthChecks("/api/health");app.Run();}catch(Exception ex){Log.Fatal(ex,"LEGAL Modello231 terminated");}finally{Log.CloseAndFlush();}
